当然！这是一个经典的 **debounce（防抖）** 函数实现，带完整注释和使用示例：

## 基础实现

```javascript
/**
 * 创建一个 debounce（防抖）函数
 * @param {Function} fn  - 需要防抖的目标函数
 * @param {number}   delay - 延迟时间（毫秒）
 * @param {boolean}  [leading=false] - 是否在延迟开始前立即执行一次
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay, leading = false) {
  let timer = null;
  let leadingCalled = false;

  const debounced = function (...args) {
    const context = this;

    // leading 模式：第一次调用时立即执行
    if (leading && !leadingCalled) {
      fn.apply(context, args);
      leadingCalled = true;
      return;
    }

    // 清除之前的定时器
    if (timer) clearTimeout(timer);

    // 设置新的定时器
    timer = setTimeout(() => {
      if (!leading) {
        fn.apply(context, args);
      }
      // 重置 leading 标记，允许下一次 leading 触发
      leadingCalled = false;
      timer = null;
    }, delay);
  };

  /**
   * 取消尚未执行的防抖调用
   */
  debounced.cancel = function () {
    if (timer) clearTimeout(timer);
    timer = null;
    leadingCalled = false;
  };

  /**
   * 立即执行并重置防抖状态
   */
  debounced.flush = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
      leadingCalled = false;
      fn.apply(this, arguments);
    }
  };

  return debounced;
}
```

---

## 简化版（最常用）

```javascript
// 最简 trailing 版（延迟结束后执行）
function debounce(fn, delay) {
  let timer = null;
  return function (...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}
```

---

## 使用示例

```javascript
// 1. 搜索输入框防抖
const searchInput = document.getElementById('search');
const handleSearch = debounce((query) => {
  console.log('发起搜索请求:', query);
  // fetch(`/api/search?q=${query}`)
}, 300);

searchInput.addEventListener('input', (e) => {
  handleSearch(e.target.value);
});

// 2. 窗口 resize 防抖
const handleResize = debounce(() => {
  console.log('窗口大小确定，重新布局');
}, 200);

window.addEventListener('resize', handleResize);

// 3. leading 模式 —— 提交按钮防止重复点击
const submit = debounce(() => {
  console.log('表单已提交');
}, 1000, true);

button.addEventListener('click', submit);

// 4. 取消与立即执行
const save = debounce(() => console.log('保存中...'), 2000);
save();
save.cancel();              // 取消这次保存
save();                     // 重新计时
save.flush();               // 立即执行
```

---

## 原理图解

```
普通调用:    f → f → f → f → f
debounce:    f………f………f (只保留最后一次，延迟结束后执行)
debounce(leading):    f → ………f → ………f (第一次立即执行，后续防抖)
```

**核心思想**：在连续高频触发的事件中，只在最后一次触发后的 `delay` 毫秒后执行一次目标函数，避免不必要的频繁调用。常见场景：搜索框、窗口 resize/scroll、按钮防重复点击。

